import{_ as t,c as a,q as n,o as p}from"./chunks/framework.qU7EqO9L.js";const o="/assets/01-all.ZeBN6jB6.jpg",i="/assets/02-kai.Bovb3lJ8.jpg",r="/assets/03-feiteng.CZMAMZg8.jpg",s="/assets/04-openkylin.BTcaz2_t.jpg",f=JSON.parse('{"title":"长沙相聚｜飞桨黑客松 × 飞腾 & openKylin Meetup 圆满落幕","description":"","frontmatter":{"title":"长沙相聚｜飞桨黑客松 × 飞腾 & openKylin Meetup 圆满落幕","date":"2026-05-17T00:00:00.000Z","author":{"name":"王凯","github":"onecatcn"}},"headers":[],"relativePath":"posts/phytium-openkylin-changsha-meetup.md","filePath":"posts/phytium-openkylin-changsha-meetup.md"}'),l={name:"posts/phytium-openkylin-changsha-meetup.md"};function g(c,e,d,u,h,_){return p(),a("div",null,[...e[0]||(e[0]=[n('<blockquote><p>5 月 17 日下午，长沙 CFC 富兴时代，飞桨黑客松的热浪与初夏一起到来。</p></blockquote><p>2026 年 5 月 17 日下午，飞桨黑客松第十期「文心合作伙伴赛道」联合飞腾与 OpenAtom openKylin，在长沙举办了线下 Meetup。约 15 位来自高校、企业和开源社区的开发者聚集于此，共同探索 AI 软硬件实践的落地路径。</p><p>这是本届黑客松第三场线下活动，也是第一场走进中部开发者社群的 Meetup。</p><figure><img src="'+o+'" alt="活动全体合影"><figcaption>活动全体合影——约 15 位开发者与飞腾、openKylin 技术团队在长沙相聚</figcaption></figure><hr><h2 id="三场分享-从赛事到实践一次讲清" tabindex="-1">三场分享，从赛事到实践一次讲清 <a class="header-anchor" href="#三场分享-从赛事到实践一次讲清" aria-label="Permalink to &quot;三场分享，从赛事到实践一次讲清&quot;">​</a></h2><p>活动分为分享与实操两个阶段。下午两点开始，连续三场技术分享依次上台。</p><p><strong>第一场：「文心大模型做 AI 自媒体」</strong> 从参赛者视角出发，结合 AI 每日参公众号的实际运营经验，介绍了如何用文心大模型与飞桨生态搭建全自动内容流水线——从热点抓取、文章生成、配图生成到微信草稿发布，全链路打通。这场分享帮助现场开发者快速建立对赛事价值的感性认知：<strong>黑客松任务不只是评测跑分，更是真实工程场景的落地实践</strong>。</p><figure><img src="'+i+'" alt="黑客松赛事与文心大模型 AI 自媒体分享"><figcaption>王凯分享：用文心大模型与飞桨生态搭建全自动 AI 自媒体流水线</figcaption></figure><hr><p><strong>第二场：「飞腾异构平台与 FastDeploy 实践」</strong> 聚焦飞腾腾云 S5000C ARM64 服务器 + NVIDIA L20 异构环境，分五个模块逐一拆解：系统环境配置、PaddlePaddle 编译适配、自定义算子与包依赖管理、分布式推理与多卡通信，以及 FastDeploy 在飞腾平台的部署全链路。现场有开发者边听边在自己的笔记本上比对环境配置，气氛相当务实。</p><figure><img src="'+r+'" alt="飞腾异构平台与 FastDeploy 实践分享"><figcaption>飞腾技术同学分享：ARM64 + NVIDIA L20 异构推理平台实战</figcaption></figure><hr><p><strong>第三场：「openKylin 社区及版本介绍」</strong> 由 openKylin 技术同学主讲，介绍了 openKylin 操作系统的发展路径、KART AI 子系统架构与 AI SDK 能力，以及端侧 AI+OS 融合的最新探索。对于想参与麒麟打卡任务或进阶任务的开发者，这场分享是最直接的入门指引。</p><figure><img src="'+s+'" alt="openKylin 社区及版本介绍分享"><figcaption>openKylin 技术同学分享：AI OS 架构与端侧智能化探索</figcaption></figure><hr><h2 id="现场实操-约-10-位开发者完成双打卡" tabindex="-1">现场实操：约 10 位开发者完成双打卡 <a class="header-anchor" href="#现场实操-约-10-位开发者完成双打卡" aria-label="Permalink to &quot;现场实操：约 10 位开发者完成双打卡&quot;">​</a></h2><p>三场分享结束后，茶歇交流简短收尾，实操环节随即开始。</p><p>现场有人带着「自己平时用飞桨但没碰过飞腾」的好奇，有人是专程冲着 openKylin 赛题来的，也有人是长沙地区工作的 PFCC / PPDE，专门过来体验一下线下黑客松。</p><p>在飞腾和 openKylin 技术同学现场指导下，大家陆续完成了环境检查、任务路径梳理、代码运行和推理验证的关键步骤。<strong>约 10 位开发者在当天下午完成了飞腾（T7）和麒麟（T11）两项打卡任务</strong>，获得礼品与证书。</p><p>飞腾 T7（基于飞腾 Arm64 V8 架构的 CPU 推理打卡）与麒麟 T11（在 openKylin 上部署 ERNIE 本地大模型），也因此从「礼品余量最多的两个赛道」，变成了「本场 Meetup 成果最集中的两个方向」。</p><hr><h2 id="没到长沙现场-线上窗口依然开着" tabindex="-1">没到长沙现场？线上窗口依然开着 <a class="header-anchor" href="#没到长沙现场-线上窗口依然开着" aria-label="Permalink to &quot;没到长沙现场？线上窗口依然开着&quot;">​</a></h2><p>打卡任务支持线上独立完成——按照任务文档配置环境、完成推理验证、将截图与日志发送至 <a href="mailto:ext_paddle_oss@baidu.com" target="_blank" rel="noreferrer">ext_paddle_oss@baidu.com</a> 及对应厂商邮箱即可，不需要到场。</p><p>进阶任务方面，飞腾 T20（基于飞腾 ARM64 的 OpenClaw 智能体协作系统）和麒麟 T28（在 openKylin 桌面上运行图形化 AI 助手 Demo）目前名额仍有空余，先提交 RFC 即进入甄选，每人奖金 2000 元。</p><p>赛事报名入口及总览信息：<a href="https://github.com/PaddlePaddle/Paddle/issues/78485" target="_blank" rel="noreferrer">PaddlePaddle/Paddle Issue #78485</a></p><p>截止时间：<strong>2026 年 6 月 26 日</strong>。</p>',27)])])}const y=t(l,[["render",g]]);export{f as __pageData,y as default};
